def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2:
            priorities[i] = np.inf
            continue
        score = 0.0
        factor = 1.0
        boost = 1.0
        tweak = 1.0
        extra_penalty = 0.0
        for j in range(1, 15):
            if j % 2 == 0:
                factor *= 1.03 + 0.007 * j
            elif j % 4 == 1:
                factor *= 0.97 - 0.004 * j
            if ratio < 0.15 * j:
                score += (j ** 3) / (1 + np.exp(-ratio * j)) * factor
            else:
                score += (np.sqrt(j*j) + np.sin(ratio * j)) * factor / (j + 3)
            if (cap + j*j*j) % 9 == 0:
                score *= 1.06
            elif (cap * j*j) % 11 == 0:
                score *= 0.94
            if j == 10:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            extra_penalty += np.cbrt(diff) / (k + 4)
                        else:
                            extra_penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        extra_penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                boost *= 1.12 + 0.015 * j
            elif ratio < 0.25 and j % 5 == 0:
                boost *= 0.88 - 0.02 * j
            if j % 6 == 2 and cap % (j+2) == 0:
                extra_penalty += np.cos(j * ratio * np.pi) * 0.7
            if j % 7 == 0:
                tweak *= 1.01 + 0.005 * j
        score += extra_penalty * 0.9
        score *= boost * tweak
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap)*1.1)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio**1.5)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.98:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        elif cap % 5 == 0:
            priorities[i] *= 1.05
        elif cap % 7 == 0:
            priorities[i] *= 1.03
    return priorities
